import React, { useEffect, useState } from "react";
import { motion } from "framer-motion";

/* 🔥 Count Up Hook */
function useCountUp(end, duration = 2000) {
  const [value, setValue] = useState(0);

  useEffect(() => {
    let startTime = null;

    const step = (timestamp) => {
      if (!startTime) startTime = timestamp;

      const progress = timestamp - startTime;
      const percent = Math.min(progress / duration, 1);

      setValue(Math.floor(percent * end));

      if (percent < 1) {
        requestAnimationFrame(step);
      }
    };

    requestAnimationFrame(step);
  }, [end, duration]);

  return value;
}

export default function Hero({ data }) {
  const { name, title, subtitle, tagline, contact, stats } = data;

  const [firstName, ...rest] = name.split(" ");
  const lastName = rest.join(" ");

  /* 🔥 Animations */
  const container = {
    hidden: {},
    show: {
      transition: {
        staggerChildren: 0.15,
      },
    },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 40 },
    show: {
      opacity: 1,
      y: 0,
      transition: { duration: 0.6, ease: "easeOut" },
    },
  };

  const cardAnim = {
    hidden: { opacity: 0, y: 50, scale: 0.95 },
    show: {
      opacity: 1,
      y: 0,
      scale: 1,
      transition: { duration: 0.5 },
    },
  };

  return (
    <>
      <style>{`
        body {
          margin: 0;
          background: #05070d;
          color: white;
          font-family: sans-serif;
          overflow-x: hidden;
        }

        .hero {
          min-height: 100vh;
          display: flex;
          align-items: center;
          justify-content: center;
          padding: clamp(60px, 8vw, 120px) 20px;
          text-align: center;
        }

        .container {
          width: 100%;
          max-width: min(1200px, 92vw);
          margin: 0 auto;
        }

        .name {
          font-size: clamp(2.2rem, 6vw, 5.5rem);
          font-weight: 800;
          line-height: 1.2;
          word-break: break-word;
        }

        .gradient {
          background: linear-gradient(90deg, #00e5ff, #7c3aed);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
        }

        .sub {
          margin-top: 14px;
          color: #aaa;
          font-size: clamp(0.95rem, 2vw, 1.2rem);
        }

        .tag {
          margin: 14px auto 0;
          color: #888;
          max-width: 650px;
          font-size: clamp(0.9rem, 2vw, 1.05rem);
          line-height: 1.6;
        }

        /* BUTTONS */
        .btns {
          display: flex;
          gap: 14px;
          margin-top: 28px;
          flex-wrap: wrap;
          justify-content: center;
        }

        .btn {
          padding: 12px 26px;
          border-radius: 999px;
          font-weight: 600;
          text-decoration: none;
          display: flex;
          justify-content: center;
          align-items: center;
          min-width: 160px;
          transition: all 0.3s ease;
        }

        .primary {
          background: #00e5ff;
          color: black;
        }

        .outline {
          border: 1px solid #444;
          color: white;
        }

        /* MOBILE */
        @media (max-width: 500px) {
          .btns {
            flex-direction: column;
          }
          .btn {
            width: 100%;
          }
        }

        /* STATS */
        .stats {
          margin-top: 60px;
          display: grid;
          grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
          gap: 20px;
        }

        .card {
          padding: 25px;
          border-radius: 16px;
          background: rgba(255,255,255,0.05);
          border: 1px solid rgba(255,255,255,0.08);
          text-align: center;
          backdrop-filter: blur(10px);
        }

        .value {
          font-size: 2.2rem;
          font-weight: 800;
          color: #00e5ff;
        }

        .label {
          margin-top: 8px;
          color: #aaa;
          font-size: 0.95rem;
        }
      `}</style>

      <section className="hero">
        <motion.div
          className="container"
          variants={container}
          initial="hidden"
          animate="show"
        >
          {/* NAME */}
          <motion.h1 className="name" variants={fadeUp}>
            {firstName} <span className="gradient">{lastName}</span>
          </motion.h1>

          {/* SUBTITLE */}
          <motion.p className="sub" variants={fadeUp}>
            {title} · <span style={{ color: "#00e5ff" }}>{subtitle}</span>
          </motion.p>

          {/* TAGLINE */}
          <motion.p className="tag" variants={fadeUp}>
            {tagline}
          </motion.p>

          {/* BUTTONS */}
          <motion.div className="btns" variants={fadeUp}>
            <motion.a
              href="mailto:your@email.com"
              className="btn primary"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              Get in Touch
            </motion.a>

            <motion.a
              href={`https://${contact.linkedin}`}
              target="_blank"
              rel="noreferrer"
              className="btn outline"
              whileHover={{ scale: 1.05 }}
            >
              LinkedIn
            </motion.a>
          </motion.div>

          {/* STATS */}
          <div className="stats">
            {stats.map((s, i) => {
              const numeric = parseInt(s.value.replace(/[^0-9]/g, ""));
              const count = useCountUp(numeric);

              return (
                <motion.div
                  key={i}
                  className="card"
                  variants={cardAnim}
                  initial={{ opacity: 0, y: 60 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: i * 0.2 }}
                  whileHover={{
                    y: -10,
                    scale: 1.07,
                    boxShadow: "0 25px 60px rgba(0,229,255,0.25)",
                  }}
                >
                  <motion.div
                    className="value"
                    initial={{ y: 25, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    transition={{ delay: i * 0.3 }}
                  >
                    {count}
                    {s.value.replace(/[0-9]/g, "")}
                  </motion.div>

                  <div className="label">{s.label}</div>
                </motion.div>
              );
            })}
          </div>
        </motion.div>
      </section>
    </>
  );
}
